pub type ModelCache = HashMap<String, Option<ModelInfo>>;

pub fn read_model_from_db_cached<DB: revm::Database>(
    db: &mut DB,
    contract: Address,
    model_name: &str,
    cache: &mut ModelCache,
) -> Result<Option<ModelInfo>, String>
where
    DB::Error: std::fmt::Display,
{
    if let Some(cached_result) = cache.get(model_name) {
        return Ok(cached_result.clone());
    }
    let result = read_model_from_db(db, contract, model_name)?;
    cache.insert(model_name.to_string(), result.clone());
    Ok(result)
}

pub fn compute_string_mapping_slot(key: &str, mapping_slot: u64) -> U256 {
    let mut slot_bytes = [0u8; 32];
    slot_bytes[24..32].copy_from_slice(&mapping_slot.to_be_bytes());

    let mut data = Vec::with_capacity(key.len() + 32);
    data.extend_from_slice(key.as_bytes());
    data.extend_from_slice(&slot_bytes);

    U256::from_be_slice(keccak256(&data).as_slice())
}

